installation.script:
#!/bin/bash
set -e
mkdir -p /mnt/server/public

# server.js - serveur Express tout-en-un (statique + API si presente)
cat > /mnt/server/server.js << 'SERVEREOF'
const express = require('express');
const path = require('path');
const fs = require('fs');

const app = express();
const port = process.env.SERVER_PORT || 3000;
const publicDir = path.join(__dirname, 'public');
const routesFile = path.join(__dirname, 'routes.js');

app.use(express.json());
app.use(express.urlencoded({ extended: true }));

// Charge les routes API custom si routes.js existe
if (fs.existsSync(routesFile)) {
    try {
        const customRoutes = require('./routes.js');
        app.use('/api', customRoutes);
        console.log('[INFO] routes.js charge sur /api');
    } catch (err) {
        console.error('[ERREUR] routes.js invalide:', err.message);
    }
} else {
    console.log('[INFO] Pas de routes.js - mode site statique seul');
}

// Cree public/ si vide
if (!fs.existsSync(publicDir)) fs.mkdirSync(publicDir);
if (fs.readdirSync(publicDir).length === 0) {
    fs.writeFileSync(path.join(publicDir, 'index.html'),
        '<!DOCTYPE html><html><head><meta charset="UTF-8"><title>WebApp</title>' +
        '<style>body{font-family:sans-serif;background:#1a1a2e;color:#eee;text-align:center;padding:80px}' +
        'h1{color:#00ff88}code{background:#16213e;padding:4px 10px;border-radius:4px;color:#00ff88}</style></head>' +
        '<body><h1>WebApp - Pret</h1>' +
        '<p>Depose ton site dans <code>public/</code></p>' +
        '<p>Pour des routes API, cree <code>routes.js</code></p></body></html>'
    );
}

// Sert le site statique
app.use(express.static(publicDir));

// Fallback SPA (pour React/Vue routing)
app.get('*', (req, res) => {
    const indexFile = path.join(publicDir, 'index.html');
    if (fs.existsSync(indexFile)) res.sendFile(indexFile);
    else res.status(404).send('Not found');
});

app.listen(port, '0.0.0.0', () => {
    console.log('[WebApp] Demarrage sur le port ' + port);
});
SERVEREOF

# package.json par defaut avec Express
cat > /mnt/server/package.json << 'PKGEOF'
{
  "name": "webapp",
  "version": "1.0.0",
  "main": "server.js",
  "dependencies": {
    "express": "^4.21.0"
  }
}
PKGEOF

# start.sh
cat > /mnt/server/start.sh << 'STARTEOF'
#!/bin/bash
cd /home/container

if [ ! -d "node_modules" ] || [ "package.json" -nt "node_modules" ]; then
    echo "[NPM] Installation des dependances..."
    npm install --no-audit --no-fund --omit=dev 2>&1 | tail -10
fi

exec node server.js
STARTEOF

chmod +x /mnt/server/start.sh
echo "[INSTALL] Termine. Depose ton site dans public/ (et optionnellement routes.js pour des API)."
